#### 官方示例: actionsample.act

```pvf
**[MOTION]** // 动作部分
    **[BASE ANI]** `../Animation_Kinol/throw.ani`
    **[SUB ANI]**
    `../../../equipment/monster/goblin/LKinolPantsAnimation/move_100.ani` 0 100    // 路径, 起始帧, 图层。
    `../../../equipment/monster/goblin/weapon09-animation/move_100.ani` 0 100
    **[/SUB ANI]**

    //mkjung 120516 [SUB ANI WITH XY] add
    **[SUB ANI WITH XY]**
        `../Animation/ScasaShout1-1.ani` 0 13 390 -160
        `../Animation/ScasaShout1-2.ani` 0 13 390 -160
        `../Animation/ScasaShout2-1.ani` 0 13 390 -160
        `../Animation/ScasaShout2-2.ani` 0 13 390 -160
    **[/SUB ANI WITH XY]**


    **[SPEECH]**
    `字符串（可用<.str字符串>替换）` 0 30  // 台词, 起始帧, 说话概率。
    `字符串（可用<.str字符串>替换）` 1 50  // 台词, 起始帧, 说话概率。
    **[/SPEECH]**

    **[SPEECH POS]**
    `字符串（可用<.str字符串>替换）` 0 30  // 台词, 起始帧, 说话概率。 x坐标, y坐标
    **[/SPEECH POS]**

    **[SOUND]**
    `SOUND_TAG` 0 // 音效, 起始帧。
    **[/SOUND]**

    **[SOUND PROBABILITY]**
    `SOUND_TAG` 0 50 // 音效, 起始帧。 概率。
    **[/SOUND PROBABILITY]**
**[/MOTION]**    // 到这里是动作部分。工具内部读取的部分。
```

#### 官方示例: actionsamplebytool.act

```pvf
{exp}动作部分{/exp}[MOTION]
	[BASE ANI]
		{must1}{string}
	[!BASE ANI]

	// 添加string标签。
	[SUB ANI]
		{exp}路径{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
			{must2}{exp}图层{/exp}{int(0:)}
		{!string}
	[/SUB ANI]

	//mkjung 120516 添加
	[SUB ANI WITH XY]
		{exp}路径{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
			{must2}{exp}图层{/exp}{int(0:)}
			{must3}{exp}X坐标{/exp}{int(:)}
			{must4}{exp}Y坐标{/exp}{int(:)}
		{!string}
	[/SUB ANI WITH XY]

	//mkjung 120517 添加
	[SUB ANI WITH XYZ]
		{exp}路径{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
			{must2}{exp}图层{/exp}{int(0:)}
			{must3}{exp}X坐标{/exp}{int(:)}
			{must4}{exp}Y坐标{/exp}{int(:)}
			{must5}{exp}Z坐标{/exp}{int(:)}
		{!string}
	[/SUB ANI WITH XYZ]


	// [SPEECH]和[SOUND]必须放在[MOTION]标签内！
	[SPEECH]
		{exp}台词标签{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
			{opt1}{exp}说话概率(%){/exp}{int(0:)}
		{!string}
	[/SPEECH]

	[SPEECH POS]
		{exp}台词标签{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
			{must2}{exp}说话概率(%){/exp}{int(0:)}
			{must3}{exp}台词输出的X坐标{/exp}{int(:)}
			{must4}{exp}台词输出的Y坐标{/exp}{int(:)}
		{!string}
	[/SPEECH POS]

	[SOUND]
		{exp}音效标签{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
		{!string}
	[/SOUND]

	[SOUND PROBABILITY]
		{exp}音效标签{/exp}{string}
			{must1}{exp}起始帧{/exp}{int(0:)}
			{must2}{exp}概率{/exp}{int(0:)}
		{!string}
	[/SOUND PROBABILITY]
[/MOTION]
```

